CREATE OR REPLACE PYTHON3 SCALAR SCRIPT UTIL.JSON_EXTRACT(
    doc   VARCHAR(2000000),
    paths VARCHAR(2000000)
) RETURNS VARCHAR(2000000) AS
import json
import re

# MariaDB JSON_EXTRACT semantics:
#   - one path  -> that match as JSON text (strings quoted, numbers bare,
#                  objects/arrays preserved)
#   - multi     -> JSON array of found values, missing paths silently skipped
#   - all miss  -> NULL
# Path grammar: "$", "$.key", "$[idx]", combinations. Wildcards are not supported;
# unsupported paths behave as "missing" (conservative -- MariaDB would error).
_TOKEN = re.compile(r"\.([A-Za-z_][A-Za-z_0-9]*)|\[(\d+)\]")
_UNSUPPORTED = re.compile(r"\*\*|\[\*\]|\?|\(")
_MISS = object()


def _resolve(node, path):
    if not isinstance(path, str) or not path.startswith("$"):
        return _MISS
    rest = path[1:]
    if _UNSUPPORTED.search(rest):
        return _MISS
    i = 0
    cur = node
    while i < len(rest):
        m = _TOKEN.match(rest, i)
        if not m:
            return _MISS
        key, idx = m.groups()
        if key is not None:
            if not isinstance(cur, dict) or key not in cur:
                return _MISS
            cur = cur[key]
        else:
            j = int(idx)
            if not isinstance(cur, list) or j >= len(cur):
                return _MISS
            cur = cur[j]
        i = m.end()
    return cur


def run(ctx):
    if ctx.doc is None or ctx.paths is None:
        return None
    try:
        data = json.loads(ctx.doc)
    except (ValueError, TypeError):
        return None
    try:
        path_list = json.loads(ctx.paths)
    except (ValueError, TypeError):
        return None
    if not isinstance(path_list, list):
        path_list = [path_list]
    found = []
    for p in path_list:
        v = _resolve(data, p)
        if v is not _MISS:
            found.append(v)
    if not found:
        return None
    if len(path_list) == 1:
        return json.dumps(found[0])
    return json.dumps(found)
/

-- === udfs/json/json_merge_preserve.sql ===
--/
CREATE OR REPLACE PYTHON3 SCALAR SCRIPT UTIL.JSON_MERGE_PRESERVE(...)
RETURNS VARCHAR(2000000) AS

import json

# MariaDB JSON_MERGE_PRESERVE semantics:
#   - Requires >= 2 args.
#   - Any NULL arg -> NULL.
#   - Adjacent objects: union by key; if a key collides, values are combined
#     (recursively merged: two objects -> nested merge; everything else -> autowrap
#     each side to an array and concatenate).
#   - Adjacent arrays: concatenate.
#   - Mixed object/array or scalars: autowrap each side to an array and concatenate.
# JSON_MERGE is a deprecated MariaDB alias and shares the same semantics; the
# preprocessor maps both names to this UDF.
# Invalid JSON in any arg -> NULL (MariaDB raises; we return NULL conservatively
# rather than aborting the whole statement).

_MISS = object()


def _parse(s):
    try:
        return json.loads(s)
    except (ValueError, TypeError):
        return _MISS


def _merge(a, b):
    if isinstance(a, dict) and isinstance(b, dict):
        out = dict(a)
        for k, v in b.items():
            out[k] = _merge(out[k], v) if k in out else v
        return out
    if isinstance(a, list) and isinstance(b, list):
        return a + b
    a_list = a if isinstance(a, list) else [a]
    b_list = b if isinstance(b, list) else [b]
    return a_list + b_list


def run(ctx):
    n = exa.meta.input_column_count
    if n < 2:
        raise ValueError('JSON_MERGE_PRESERVE requires at least 2 arguments')
    vals = []
    for i in range(n):
        s = ctx[i]
        if s is None:
            return None
        v = _parse(s)
        if v is _MISS:
            return None
        vals.append(v)
    result = vals[0]
    for nxt in vals[1:]:
        result = _merge(result, nxt)
    return json.dumps(result, ensure_ascii=False)
/

