CREATE OR REPLACE PYTHON3 SCALAR SCRIPT UTIL.JSON_OBJECT(...)
RETURNS VARCHAR(2000000) AS

import json
import decimal
import datetime


def default_serializer(obj):
    if isinstance(obj, decimal.Decimal):
        if obj == obj.to_integral_value():
            return int(obj)
        return float(obj)
    if isinstance(obj, datetime.datetime):
        return obj.isoformat()
    if isinstance(obj, datetime.date):
        return obj.isoformat()
    raise TypeError(f'Object of type {type(obj).__name__} is not JSON serializable')


def run(ctx):
    n = exa.meta.input_column_count
    if n % 2 != 0:
        raise ValueError('JSON_OBJECT requires an even number of arguments (key-value pairs)')
    obj = {}
    for i in range(0, n, 2):
        key = ctx[i]
        if key is None:
            raise ValueError('JSON_OBJECT key must not be NULL')
        key = str(key)
        value = ctx[i + 1]
        # If a value is a string that looks like a JSON container (object or
        # array), parse it and embed the parsed value. Without this, a nested
        # UTIL.JSON_OBJECT (or JSON_EXTRACT / JSON_MERGE_PRESERVE) returns
        # JSON text that the outer call would re-quote as a string, producing
        # escaped output instead of properly nested JSON. Bare literals like
        # 'true' / 'null' / '123' are NOT parsed — that would change the
        # meaning of user-supplied scalar strings. A caller who genuinely
        # supplies a string that opens with '{' or '[' and happens to be valid
        # JSON will see it interpreted as JSON; this matches the behavior of
        # MariaDB's implicit JSON typing.
        if isinstance(value, str) and value[:1] in ('{', '['):
            try:
                value = json.loads(value)
            except ValueError:
                pass
        obj[key] = value
    return json.dumps(obj, default=default_serializer, ensure_ascii=False)
/

-- === udfs/json/json_objectagg.sql ===
--/
CREATE OR REPLACE PYTHON3 SCALAR SCRIPT UTIL.JSON_OBJECTAGG(s VARCHAR(2000000))
RETURNS VARCHAR(2000000) AS

import json


# MariaDB JSON_OBJECTAGG(key, value) aggregates rows into a single JSON object.
# Exasol implements user-defined aggregates as SET SCRIPTs, but emitting SET
# SCRIPTs cannot appear inside any expression context (scalar subqueries,
# argument positions, CTE referenced from an outer expression — all rejected
# with "emitting function in expression"). MariaDB JSON_OBJECTAGG routinely
# appears inside JSON_OBJECT(...) or as a scalar subquery, so a SET SCRIPT
# wouldn't cover real workloads.
#
# Workaround: the preprocessor rewrites MariaDB-form JSON_OBJECTAGG(k, v) into
#   UTIL.JSON_OBJECTAGG(LISTAGG(UTIL.JSON_OBJECT(k, v), ','))
# LISTAGG is a standard SQL aggregate (expression-safe). It concatenates each
# row's mini JSON object — produced by UTIL.JSON_OBJECT, which handles type
# coercion, JSON nesting, and NULL-key errors — into one comma-joined string.
# This UDF then wraps that string in [...] to make a JSON array, parses, and
# merges the per-row objects into one.
#
# Semantics:
#   - Empty group -> LISTAGG returns NULL -> we return NULL. Matches MariaDB.
#   - NULL key -> UTIL.JSON_OBJECT raises -> error propagates. Matches MariaDB.
#   - NULL value -> embedded as JSON `null`. Matches MariaDB.
#   - Duplicate keys -> last-write-wins (`dict.update`). Matches MariaDB's
#     "rows processed in unspecified order, later one wins" behavior.
#   - Aggregation order is whatever LISTAGG produces (no WITHIN GROUP ORDER BY
#     added by the preprocessor, so unspecified); same as MariaDB.


def run(ctx):
    s = ctx[0]
    if s is None:
        return None
    arr = json.loads('[' + s + ']')
    out = {}
    for o in arr:
        out.update(o)
    return json.dumps(out, ensure_ascii=False)
/

-- === udfs/json/json_quote.sql ===
--/
CREATE OR REPLACE PYTHON3 SCALAR SCRIPT UTIL.JSON_QUOTE(
    val VARCHAR(2000000)
) RETURNS VARCHAR(2000000) AS
import json

# MariaDB JSON_QUOTE semantics: wrap the argument as a JSON string literal,
# escaping interior quotes and control characters.
#   NULL          -> NULL
#   'hello'       -> '"hello"'
#   'a"b'         -> '"a\"b"'           (interior " escaped)
#   'a' + LF +'b' -> '"a\nb"'           (control chars escaped)
#   'null'        -> '"null"'           (no JSON parsing; always a string)
# Inverse of UTIL.JSON_UNQUOTE for string inputs.
#
# Exasol quirk: VARCHAR '' is indistinguishable from NULL at the UDF boundary
# (Exasol treats '' IS NULL as TRUE), so JSON_QUOTE('') returns NULL on Exasol
# even though MariaDB returns '""'. This is a platform-level limitation, not a
# UDF bug — the run() body would otherwise produce '""' on a literal ''.


def run(ctx):
    s = ctx.val
    if s is None:
        return None
    return json.dumps(s)
/

-- === udfs/json/json_unquote.sql ===
--/
CREATE OR REPLACE PYTHON3 SCALAR SCRIPT UTIL.JSON_UNQUOTE(
    val VARCHAR(2000000)
) RETURNS VARCHAR(2000000) AS
import json

# MariaDB JSON_UNQUOTE semantics (lenient variant; MySQL is stricter):
#   NULL                 -> NULL
#   '"hello"'            -> 'hello'             (JSON string -> unescaped text)
#   '"a\\nb"'            -> 'a' + LF + 'b'      (JSON escapes resolved)
#   anything else        -> input unchanged     (numbers, objects, arrays,
#                                                already-unquoted text, garbage)
# A value counts as a JSON string only if it parses to a Python str. Objects
# and arrays pass through verbatim, matching MariaDB's behavior.


def run(ctx):
    s = ctx.val
    if s is None:
        return None
    if len(s) >= 2 and s[0] == '"' and s[-1] == '"':
        try:
            v = json.loads(s)
        except ValueError:
            return s
        if isinstance(v, str):
            return v
    return s
/

